                                .stroke(Color.accentColor.opacity(0.3), lineWidth: 1.5)
                        )
                        .frame(width: diameter, height: diameter)
                        .position(x: geo.size.width / 2, y: geo.size.height / 2)
                        .allowsHitTesting(false)
